    saveAgent() {
        if (!this.newAgent.name || !this.newAgent.role || !this.newAgent.goal) {
            alert('Name, Role, and Goal are mandatory.');
            return;
        }
        this.isSaving = true;
        fetch('http://localhost:8000/ai-agents', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-TOKEN': 'SYpXJSagYvuGpVxlKVNPZNKLPWVL19fiIGeXoSjo',
                'Accept': 'application/json'
            },
            body: JSON.stringify(this.newAgent)
        })
        .then(res => res.json())
        .then(data => {
            if (data.success) {
                window.location.reload();
            } else {
                alert('Failed to create agent.');
                this.isSaving = false;
            }
        })
        .catch(err => {
            console.error(err);
            this.isSaving = false;
        });
    },

    editAgent(agent) {
        this.selectedAgent = { ...agent };
        this.showEditModal = true;
    },

    updateAgent() {
        this.isSaving = true;
        fetch(`/ai-agents/${this.selectedAgent.id}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json',
                'X-CSRF-TOKEN': 'SYpXJSagYvuGpVxlKVNPZNKLPWVL19fiIGeXoSjo',
                'Accept': 'application/json'
            },
            body: JSON.stringify(this.selectedAgent)
        })
        .then(res => res.json())
        .then(data => {
            if (data.success) {
                window.location.reload();
            } else {
                alert('Failed to update agent.');
                this.isSaving = false;
            }
        })
        .catch(err => {
            console.error(err);
            this.isSaving = false;
        });
    },

    deleteAgent(id) {
        if(confirm('Decommission this AI Agent?')) {
            fetch(`/ai-agents/${id}`, {
                method: 'DELETE',
                headers: { 'X-CSRF-TOKEN': 'SYpXJSagYvuGpVxlKVNPZNKLPWVL19fiIGeXoSjo' }
            }).then(() => window.location.reload());
        }
    }
}
